# Python 3.10+ — no typing import needed for union
def get_item(uid: str) -> order_models.Order | None:
    return order_models.Order.objects.filter(pk=uid).first()

# Built-in generics — no List import
def get_orders(user: user_models.User) -> list[order_models.Order]:
    return list(order_models.Order.objects.filter(user=user))
